function textFromResponse(resp) { if (typeof resp.output_text === 'string') return resp.output_text; if (!Array.isArray(resp.output)) return ''; return resp.output.map((item) => (item.content || []).map((c) => c.text || c.output_text || '').join('')).join(''); }
function parseJsonLoose(text) { const cleaned = String(text || '').replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```$/i, '').trim(); try { return JSON.parse(cleaned); } catch (error) { const start = cleaned.indexOf('{'); const end = cleaned.lastIndexOf('}'); if (start >= 0 && end > start) return JSON.parse(cleaned.slice(start, end + 1)); throw error; } }
const run = $items('初始化运行信息')[0].json;
const parsed = parseJsonLoose(textFromResponse($json));
const hotspots = Array.isArray(parsed.hotspots) ? parsed.hotspots : (Array.isArray(parsed['热点']) ? parsed['热点'] : []);
if (hotspots.length === 0) throw new Error('OpenAI 联网搜索没有返回 hotspots 数组，请打开上一个节点查看原始输出。');
return [{ json: { ...run, search_result: parsed, hotspots } }];

function textFromResponse(resp) { if (typeof resp.output_text === 'string') return resp.output_text; if (!Array.isArray(resp.output)) return ''; return resp.output.map((item) => (item.content || []).map((c) => c.text || c.output_text || '').join('')).join(''); }
function parseJsonLoose(text) { const cleaned = String(text || '').replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```$/i, '').trim(); try { return JSON.parse(cleaned); } catch (error) { const start = cleaned.indexOf('{'); const end = cleaned.lastIndexOf('}'); if (start >= 0 && end > start) return JSON.parse(cleaned.slice(start, end + 1)); throw error; } }
function pick(obj, keys, fallback = '') { for (const key of keys) if (obj[key] !== undefined && obj[key] !== null && obj[key] !== '') return obj[key]; return fallback; }
const base = $items('解析搜索结果')[0].json;
const parsed = parseJsonLoose(textFromResponse($json));
const rawTopics = Array.isArray(parsed.topics) ? parsed.topics : (Array.isArray(parsed['选题']) ? parsed['选题'] : []);
if (rawTopics.length < 5) throw new Error('OpenAI 选题生成返回不足5个选题，请打开上一个节点检查输出。');
const topics = rawTopics.slice(0, 5).map((topic, index) => {
  const heat = Number(pick(topic, ['热度分', 'heat_score', 'heatScore'], 0));
  const value = Number(pick(topic, ['转化价值分', 'conversion_score', 'conversionValueScore'], 0));
  const total = Number(pick(topic, ['总分', 'total_score', 'totalScore'], Math.round(heat * 0.6 + value * 0.4)));
  const source = pick(topic, ['热点来源URL', 'source_urls', 'sourceLinks'], '');
  const sourceText = Array.isArray(source) ? source.map((s) => typeof s === 'string' ? s : (s.url || '')).filter(Boolean).join('\n') : String(source || '');
  return {
    '日期': base.run_date,
    '选题ID': pick(topic, ['选题ID', 'topic_id'], 'AI-' + base.run_date.replace(/-/g, '') + '-' + String(index + 1).padStart(2, '0')),
    '选题标题': pick(topic, ['选题标题', 'title', 'topic'], ''),
    '角度': pick(topic, ['角度', 'angle'], ''),
    '目标人群': pick(topic, ['目标人群', 'target_audience'], ''),
    '热点来源URL': sourceText,
    '热点摘要': pick(topic, ['热点摘要', 'summary'], ''),
    '热度分': heat,
    '转化价值分': value,
    '总分': total,
    '状态': pick(topic, ['状态', 'status'], '待生成脚本')
  };
});
topics.sort((a, b) => Number(b['总分']) - Number(a['总分']));
return [{ json: { ...base, topics } }];

function textFromResponse(resp) { if (typeof resp.output_text === 'string') return resp.output_text; if (!Array.isArray(resp.output)) return ''; return resp.output.map((item) => (item.content || []).map((c) => c.text || c.output_text || '').join('')).join(''); }
function parseJsonLoose(text) { const cleaned = String(text || '').replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```$/i, '').trim(); try { return JSON.parse(cleaned); } catch (error) { const start = cleaned.indexOf('{'); const end = cleaned.lastIndexOf('}'); if (start >= 0 && end > start) return JSON.parse(cleaned.slice(start, end + 1)); throw error; } }
const base = $items('回到选题汇总')[0].json;
let selection = {};
try { selection = parseJsonLoose(textFromResponse($json)); } catch (error) { selection = {}; }
const topics = base.topics || [];
const pickedId = selection.selected_topic_id || selection['选题ID'] || '';
const selected = topics.find((topic) => topic['选题ID'] === pickedId) || topics.slice().sort((a, b) => Number(b['总分']) - Number(a['总分']))[0];
if (!selected) throw new Error('没有可用的最高分选题。');
return [{ json: { ...base, selected_topic: selected, selection_reason: selection.reason || '按总分最高自动选择' } }];

function textFromResponse(resp) { if (typeof resp.output_text === 'string') return resp.output_text; if (!Array.isArray(resp.output)) return ''; return resp.output.map((item) => (item.content || []).map((c) => c.text || c.output_text || '').join('')).join(''); }
function parseJsonLoose(text) { const cleaned = String(text || '').replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```$/i, '').trim(); try { return JSON.parse(cleaned); } catch (error) { const start = cleaned.indexOf('{'); const end = cleaned.lastIndexOf('}'); if (start >= 0 && end > start) return JSON.parse(cleaned.slice(start, end + 1)); throw error; } }
function pick(obj, keys, fallback = '') { for (const key of keys) if (obj[key] !== undefined && obj[key] !== null && obj[key] !== '') return obj[key]; return fallback; }
const base = $items('解析最高分选题')[0].json;
const parsed = parseJsonLoose(textFromResponse($json));
const selected = base.selected_topic;
const combinedText = JSON.stringify(parsed);
const forbidden = /(微信|weixin|wechat|vx|v信|手机号|电话|QQ|QQ群|邮箱|email|Telegram|WhatsApp|加我|进群|私信领资料|扫码)/i;
const risks = [];
if (forbidden.test(combinedText)) risks.push('疑似出现站外联系方式，请人工修改');
const sourceUrls = String(pick(parsed, ['事实来源URL', 'fact_source_urls', 'sources'], selected['热点来源URL'] || '')).trim() || selected['热点来源URL'];
if (!sourceUrls) risks.push('缺少事实来源链接');
const scriptRow = {
  '日期': base.run_date,
  '脚本ID': pick(parsed, ['脚本ID', 'script_id'], 'SCRIPT-' + base.run_date.replace(/-/g, '') + '-01'),
  '选题ID': selected['选题ID'],
  '选题标题': selected['选题标题'],
  '开头钩子': pick(parsed, ['开头钩子', 'opening_hook'], ''),
  '正文脚本': pick(parsed, ['正文脚本', 'body_script', 'script'], ''),
  '结尾引导': pick(parsed, ['结尾引导', 'ending_cta'], ''),
  '标题': pick(parsed, ['标题', 'title'], selected['选题标题']),
  '封面文案': pick(parsed, ['封面文案', 'cover_text'], ''),
  '评论区引导语': pick(parsed, ['评论区引导语', 'comment_guide'], ''),
  '事实来源URL': sourceUrls,
  '合规风险': [pick(parsed, ['合规风险', 'compliance_risk'], ''), ...risks].filter(Boolean).join('；') || '未发现明显风险，仍需人工审核',
  '状态': risks.length ? '需要人工修改' : '待人工审核'
};
return [{ json: { ...base, script_row: scriptRow } }];

const base = $items('解析脚本')[0].json;
const selected = base.selected_topic;
const script = base.script_row;
return [{ json: {
  '日期': base.run_date,
  '任务时间': base.run_time,
  '任务类型': '01_每日AI选题和脚本',
  '状态': 'success',
  '负责人': 'n8n 自动化',
  '备注': '已生成5个选题并写入选题库；最高分选题：' + selected['选题标题'] + '；脚本ID：' + script['脚本ID'] + '；脚本状态：' + script['状态'] + '；发布前必须人工审核。'
} }];
